CREATE TRIGGER [dbo].[BillOfProcessProcessWorkElement_History]ON [dbo].[BillOfProcessProcessWorkElement]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.BillOfProcessProcessWorkElementId IS NOT NULL AND d.BillOfProcessProcessWorkElementId IS NULL THEN 'I' 		WHEN i.BillOfProcessProcessWorkElementId IS NOT NULL AND d.BillOfProcessProcessWorkElementId IS NOT NULL THEN 'U' 		WHEN i.BillOfProcessProcessWorkElementId IS NULL AND d.BillOfProcessProcessWorkElementId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.BillOfProcessProcessWorkElementId = d.BillOfProcessProcessWorkElementId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_BillOfProcessProcessWorkElement([BillOfProcessProcessWorkElementId], [BillOfProcessProcessId], [WorkElementTypeId], [Name], [Sequence], [IsRequired], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [BillOfProcessProcessWorkElementId], [BillOfProcessProcessId], [WorkElementTypeId], [Name], [Sequence], [IsRequired], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_BillOfProcessProcessWorkElement([BillOfProcessProcessWorkElementId], [BillOfProcessProcessId], [WorkElementTypeId], [Name], [Sequence], [IsRequired], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [BillOfProcessProcessWorkElementId], [BillOfProcessProcessId], [WorkElementTypeId], [Name], [Sequence], [IsRequired], [IsActive], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND